// ── 送資料到 Google Sheets ─────────────────────────────
async function sendToSheet(payload) {
  if (!SHEET_URL) return;
  try {
    await fetch(SHEET_URL, {
      method: "POST", mode: "no-cors",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
  } catch (e) { console.warn("資料送出失敗:", e); }
}

